// components/layout/AppShell.tsx
// Layout 2 niveaux — TopNav (7 sections) + Sidebar contextuelle + Contenu
// Flex layout contraint à 1440px — pas de fixed positioning sur desktop

import React from 'react';
import TopNav from './TopNav';
import Sidebar from './Sidebar';

interface AppShellProps {
  activeSection: string;
  onSectionChange: (section: string) => void;
  activePage: string;
  onPageChange: (page: string) => void;
  credits: number;
  plan: string;
  user: { name: string; email: string } | null;
  onOpenCommandPalette?: () => void;
  onLogoClick?: () => void;
  children: React.ReactNode;
}

export default function AppShell({
  activeSection,
  onSectionChange,
  activePage,
  onPageChange,
  credits,
  plan,
  user,
  onOpenCommandPalette,
  onLogoClick,
  children,
}: AppShellProps) {
  const hasSidebar = activeSection !== 'dashboard';

  return (
    <div className="h-screen flex flex-col bg-[var(--bg-base)]">

      {/* BARRE HORIZONTALE — in-flow, sticky */}
      <TopNav
        activeSection={activeSection}
        onSectionChange={onSectionChange}
        credits={credits}
        user={user}
        onOpenCommandPalette={onOpenCommandPalette}
        onLogoClick={onLogoClick}
      />

      {/* BODY — sidebar + contenu */}
      <div className="flex flex-1 min-h-0">

import type { Config } from "tailwindcss";

const config: Config = {
  darkMode: ["class"],
  content: [
    "./index.html",
    "./App.tsx",
    "./index.tsx",
    "./pages/**/*.{ts,tsx}",
    "./components/**/*.{ts,tsx}",
    "./lib/**/*.{ts,tsx}",
    "./i18n/**/*.{ts,tsx}",
    "./src/**/*.{ts,tsx}",
  ],
  theme: {
    extend: {
      colors: {
        primary: "#7c3aed",
        leadradar: {
          bg: "#0B0F1A",
          card: "#111827",
          border: "#1E293B",
          accent: "#10B981",
          immobilier: "#FF6B35",
          coaching: "#8B5CF6",
          btp: "#10B981",
          burning: "#EF4444",
          hot: "#F97316",
          warm: "#F59E0B",
          cold: "#64748B",
          text: "#F8FAFC",
          muted: "#94A3B8",
        },
      },
      fontFamily: {
        sans: ["Geist Sans", "Inter", "system-ui", "sans-serif"],
        mono: ["Geist Mono", "SF Mono", "Consolas", "monospace"],
        serif: ["Playfair Display", "Georgia", "serif"],
        outfit: ["Outfit", "system-ui", "sans-serif"],
      },
      animation: {
        "pulse-live": "pulseLive 1.6s ease-in-out infinite",
        "slide-in": "slideIn 400ms ease-out",
      },
      keyframes: {
        pulseLive: {
